ade": {"legs": [{"instrument": "DGS2", "weight": -0.5}, {"instrument": "DGS10", "weight": 0.5}], "conviction": 0.3, "rationale": "Small steepener reflecting curve_slope's shallow uptick, sized down given term_premium's anchored long-end pull and no front-end tightening catalyst from labor."}}

